INSERT INTO projects (
  slug, title_fr, title_en, category, excerpt_fr, excerpt_en, description_fr, description_en,
  client_name_fr, client_name_en, year, location_fr, location_en, status, cover_url, gallery, tags,
  budget, featured, sort_order
)
SELECT
  slug,
  title_fr,
  title_en,
  category,
  excerpt_fr,
  excerpt_en,
  'Contexte : ' || problem_fr || E'\n\nSolution : ' || solution_fr || E'\n\nRésultat : ' || result_fr || E'\n\nServices : ' || array_to_string(services, ', ') || E'\n\nLivrables : ' || deliverables_fr,
  'Problem: ' || problem_en || E'\n\nSolution: ' || solution_en || E'\n\nResult: ' || result_en || E'\n\nServices: ' || array_to_string(services, ', ') || E'\n\nDeliverables: ' || deliverables_en,
  client_name_fr,
  client_name_en,
  year,
  location_fr,
  location_en,
  'published',
  NULL,
  ARRAY[]::text[],
  services,
  0,
  featured,
  sort_order
FROM project_seed
ORDER BY sort_order;

DO $$
DECLARE
  project_count integer;
  slug_count integer;
  featured_count integer;
  invalid_category_count integer;
BEGIN
  SELECT count(*) INTO project_count FROM projects;
  SELECT count(DISTINCT slug) INTO slug_count FROM projects;
  SELECT count(*) INTO featured_count FROM projects WHERE featured = true;
  SELECT count(*) INTO invalid_category_count
  FROM projects
  WHERE category NOT IN (
    'brand-identity',
    'graphic-design',
    'packaging-design',
    'social-media-campaign',
    'photography',
    'video-production',
    'motion-graphics',
    'ui-ux-design',
    'web-development',
    'full-stack-development',
    'audio-engineering',
    'interior-exterior-visual-concepts'
  );

  IF project_count <> 80 THEN
    RAISE EXCEPTION 'Expected 80 projects, found %', project_count;
  END IF;

  IF slug_count <> 80 THEN
    RAISE EXCEPTION 'Expected 80 unique slugs, found %', slug_count;
  END IF;

  IF featured_count NOT BETWEEN 12 AND 16 THEN
    RAISE EXCEPTION 'Expected 12 to 16 featured projects, found %', featured_count;
  END IF;

  IF invalid_category_count <> 0 THEN
    RAISE EXCEPTION 'Found projects outside approved category list';
  END IF;

  IF EXISTS (
    SELECT 1
    FROM works_categories
    WHERE name_en IN ('AI Tools', 'Cybersecurity', 'DevOps', 'Events & Festivals')
       OR slug IN ('ai-tools', 'cybersecurity', 'devops', 'events-festivals')
  ) THEN
    RAISE EXCEPTION 'Forbidden main category detected';
  END IF;

  RAISE NOTICE 'Premium portfolio seed completed: 80 projects, % featured projects.', featured_count;
END $$;

COMMIT;
